+#[test]
+fn step_constructor_coverage_is_consistent() {
+    let coverage: Value =
+        serde_json::from_str(STEP_COVERAGE_JSON).expect("step coverage must parse");
+    let constructors = coverage
+        .get("constructors")
+        .and_then(Value::as_array)
